class _DeepLinkHandlerState extends State<DeepLinkHandler> {
  String? _initialLink;
  StreamSubscription? _sub;

  @override
  void initState() {
    super.initState();
    _initUniLinks();
  }

  void _initUniLinks() async {
    try {
      _initialLink = await getInitialLink();
      if (_initialLink != null) {
        _handleLink(_initialLink!);
      }
    } catch (e) {
      print('Error getting initial link: $e');
    }

    _sub = uriLinkStream.listen((Uri? uri) {
      if (uri != null) {
        _handleLink(uri.toString());
      }
    }, onError: (err) {
      print('Error listening to link: $err');
    });
  }

  void _handleLink(String link) {
    final Uri uri = Uri.parse(link);
    final path = uri.path;
    final params = uri.queryParameters;
    
    WidgetsBinding.instance.addPostFrameCallback((_) {
      _navigateToRoute(path, params);
    });
  }

  void _navigateToRoute(String path, Map<String, String> params) {
    final navigator = Navigator.of(context);
    
    if (path.startsWith('/profile')) {
      final id = params['id'] ?? '';
      navigator.pushNamed('/profile', arguments: {'id': id});
    } else if (path.startsWith('/payment')) {
      final action = params['action'] ?? '';
      navigator.pushNamed('/payment', arguments: {'action': action});
    } else if (path.startsWith('/campaign')) {
      final campaignId = params['id'] ?? '';
      navigator.pushNamed('/campaign', arguments: {'id': campaignId});
    }
  }

  @override
  void dispose() {
    _sub?.cancel();
    super.dispose();
  }

