class AppRouter {
  static Route<dynamic> generateRoute(RouteSettings settings) {
    final args = settings.arguments;
    
    switch (settings.name) {
      case '/profile':
        return MaterialPageRoute(
          builder: (_) => ProfileScreen(id: args?['id'] as String? ?? ''),
        );
      case '/payment':
        return MaterialPageRoute(
          builder: (_) => PaymentScreen(action: args?['action'] as String? ?? ''),
        );
      case '/campaign':
        return MaterialPageRoute(
          builder: (_) => CampaignScreen(id: args?['id'] as String? ?? ''),
        );
      default:
        return MaterialPageRoute(builder: (_) => Scaffold(body: Center(child: Text('No route found'))));
    }
  }
}

